Todo -> {
  String:title
  bool:done -> false
}

Add -> { Todo:item }
Toggle -> { i32:index }

TodoApp -> {
  List{T <- Todo}:items >>- Add -> {}
  Add -< e {
    items -<< items + e.item
  }
  Toggle -< e {
    items -<< items ? {
      Todo:(t) -> Todo{done -> true}
      -> t
    }
  }
}
